void screen_update_language(lang_type_t lang)
{
    aic_set_language(lang);
    screen_update_current_language();
}

void screen_update_current_language()
{
    screen_t *scr = screen_get(&ui_manager);
    lv_obj_set_style_text_font(scr->SETTING_LABEL, aic_get_multi_lang_font(30), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(scr->SETTING_LABEL, aic_get_translation(SETTING));

    lv_obj_set_style_text_font(scr->ENGLISH_BTN, aic_get_multi_lang_font(20), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lv_obj_get_child(scr->ENGLISH_BTN, 0), aic_get_translation(ENGLISH));

    lv_obj_set_style_text_font(scr->CHINESE_BTN, aic_get_multi_lang_font(20), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lv_obj_get_child(scr->CHINESE_BTN, 0), aic_get_translation(CHINESE));

    lv_obj_set_style_text_font(scr->JAPANESE_BTN, aic_get_multi_lang_font(20), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lv_obj_get_child(scr->JAPANESE_BTN, 0), aic_get_translation(JAPANESE));

    lv_obj_set_style_text_font(scr->LAN_LABEL, aic_get_multi_lang_font(25), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(scr->LAN_LABEL, aic_get_translation(LANGUAGE));

    lv_obj_set_style_text_font(scr->DISPLAY_LABEL, aic_get_multi_lang_font(25), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(scr->DISPLAY_LABEL, aic_get_translation(DISPLAY));

    lv_obj_set_style_text_font(scr->DARK_BTN, aic_get_multi_lang_font(20), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lv_obj_get_child(scr->DARK_BTN, 0), aic_get_translation(DARK));

    lv_obj_set_style_text_font(scr->LIGHT_BTN, aic_get_multi_lang_font(20), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lv_obj_get_child(scr->LIGHT_BTN, 0), aic_get_translation(LIGHT));

    lv_obj_set_style_text_font(scr->LAMP_LABEL, aic_get_multi_lang_font(20), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(scr->LAMP_LABEL, aic_get_translation(LAMP));

}

